const express = require('express');
const axios = require('axios');

// Set up Express.js app
const app = express();

// Set up session storage (e.g., using cookie-session)
app.use(require('cookie-session')({
  name: 'session',
  keys: ['secret-key'],
  maxAge: 30 * 24 * 60 * 60 * 1000 // 30 days
}));

// Redirect to authorization URL
const authUrl = 'https://example.com/oauth/authorize';
app.get('/login', (req, res) => {
  const clientId = 'your_client_id';
  const redirectUri = 'http://localhost:3000/callback';
  const scope = 'scope1 scope2';

  const url = `${authUrl}?client_id=${clientId}&redirect_uri=${redirectUri}&response_type=token&scope=${scope}`;
  res.redirect(url);
});

// Handle authorization callback
app.get('/callback', (req, res) => {
  const accessToken = req.query.access_token;
  if (!accessToken) {
    res.status(401).send('Unauthorized');
    return;
  }

  // Store access token in session storage
  req.session.accessToken = accessToken;

  // Make API call using access token
  axios.get('https://api.example.com/protected-resource', {
    headers: {
      Authorization: `Bearer ${accessToken}`
    }
  })
  .then(response => {
    console.log(response.data);
    res.send('API call successful');
  })
  .catch(error => {
    console.error(error);
    res.status(500).send('Error making API call');
  });
});

// Handle protected routes
app.get('/protected', (req, res) => {
  const accessToken = req.session.accessToken;
  if (!accessToken) {
    res.status(401).send('Unauthorized');
    return;
  }

  // Make API call using access token
  axios.get('https://api.example.com/protected-resource', {
    headers: {
      Authorization: `Bearer ${accessToken}`
    }
  })
  .then(response => {
    console.log(response.data);
    res.send('API call successful');
  })
  .catch(error => {
    console.error(error);
    res.status(500).send('Error making API call');
  });
});

// Start Express.js server
const port = 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});